# ══════════════════════════════════════════════════════════════════
# ② OLS 重回帰（statsmodels）
# ══════════════════════════════════════════════════════════════════
if HAS_SM:
    print("\n[② OLS 重回帰分析 (statsmodels)]")
    for name, (X, feat_names) in feature_sets.items():
        print(f"\n  ── {name} ──")
        X_sc  = StandardScaler().fit_transform(X)
        X_ols = sm.add_constant(X_sc)
        col_names = ["const"] + feat_names
        model = sm.OLS(y, X_ols).fit()

        # 係数テーブル
        print(f"  {'変数':<15}  {'係数':>9}  {'t値':>8}  {'p値':>10}  {'有意'}")
        print("  " + "-"*_sage_const_55 )
        for j, cname in enumerate(col_names):
            coef = model.params[j]
            tval = model.tvalues[j]
            pval = model.pvalues[j]
            sig  = "***" if pval<_sage_const_0p001  else ("**" if pval<_sage_const_0p01  else ("*" if pval<_sage_const_0p05  else ""))
            print(f"  {cname:<15}  {coef:9.4f}  {tval:8.3f}  {pval:10.4e}  {sig}")
        print(f"  R²={model.rsquared:.4f}  Adj.R²={model.rsquared_adj:.4f}"
              f"  F={model.fvalue:.2f}  F_p={model.f_pvalue:.3e}")

        # VIF（特徴量が 2 個以上のとき）
        if X.shape[_sage_const_1 ] >= _sage_const_2 :
            print(f"\n  [VIF 診断]")
