ax.set_title("Lasso Coefficients (standardized features)")
plt.colorbar(im, ax=ax)
for i in range(_sage_const_5 ):
    for j in range(len(B_feat_names)):
        ax.text(j, i, f"{lasso_coefs[i,j]:.2f}", ha="center", va="center",
                fontsize=_sage_const_8 , color="black")

ax = axes[_sage_const_1 ]
mean_c = lasso_coefs.mean(axis=_sage_const_0 )
std_c  = lasso_coefs.std(axis=_sage_const_0 )
