ax.bar(range(len(B_feat_names)), mean_c, yerr=std_c, capsize=_sage_const_5 ,
       color=colors_bar, alpha=_sage_const_0p85 )
ax.axhline(_sage_const_0 , color="black", lw=_sage_const_0p8 )
ax.set_xticks(range(len(B_feat_names)))
ax.set_xticklabels(B_feat_names, rotation=_sage_const_30 , ha="right", fontsize=_sage_const_9 )
ax.set_ylabel("Mean Lasso coefficient (±std)")
ax.set_title("Feature Importance: Mean ± Std across Folds\n(gray = collapsed to 0)")
ax.grid(True, alpha=_sage_const_0p3 , axis="y")

plt.tight_layout()
fig.savefig(OUT / "W7-2a_fig2_lasso_stability.png", dpi=_sage_const_120 , bbox_inches="tight")
