print("\n" + "=" * _sage_const_65 )
print("  W-7-2a 総合サマリー")
print("=" * _sage_const_65 )

ref_r2  = cv_r2_results["A: Burau(1/2) のみ"]["ridge"]
best_r2 = max(v["ridge"] for v in cv_r2_results.values())
best_fs = max(cv_r2_results, key=lambda k: cv_r2_results[k]["ridge"])

print(f"\n  ベースライン（Burau 1点 Ridge）: CV R²={ref_r2:.4f}")
print(f"  最良（{best_fs}）: CV R²={best_r2:.4f}")
delta_r2 = best_r2 - ref_r2
if delta_r2 > _sage_const_0p01 :
    print(f"  → R² が +{delta_r2:.4f} 改善 ★ Burau 複数評価点に情報量あり")
elif delta_r2 > _sage_const_0p002 :
    print(f"  → R² が +{delta_r2:.4f} わずかに改善（誤差範囲の可能性）")
else:
    print(f"  → R² の変化 {delta_r2:+.4f}  ≒ 変化なし")
    print(f"    → Burau(1/2) の単点評価で既に情報量を使い切っている可能性")
    print(f"    → 次は Phase 2（固有値スペクトル）または LKB へ進む価値あり")

print(f"\n  W-7 天井（CV R²≈0.27）との比較:")
print(f"    最良 CV R²={best_r2:.4f}  天井={_sage_const_0p27 :.4f}  差={best_r2-_sage_const_0p27 :+.4f}")

print(f"\n  Precision@50 比較:")
best_p50 = max(prec_results[n][_sage_const_50 ] for n in feature_sets)
best_p50_fs = max(feature_sets, key=lambda n: prec_results[n][_sage_const_50 ])
print(f"    最良: {best_p50_fs} → P@50={best_p50:.4f}")
print(f"    3-Stage-25% 参考値:               P@50=0.8680")
print(f"    差: {best_p50-_sage_const_0p868 :+.4f}")

print(f"\n  次のステップ:")
if best_r2 > _sage_const_0p30 :
    print(f"  → Phase 2 へ：固有値スペクトルでさらに掘る価値あり")
else:
    print(f"  → Phase 2 へ：Burau 固有値スペクトル（trace より豊富）を試す")
    print(f"     または Phase 3 へ：LKB 忠実表現（非忠実性が天井の原因かの判定）")

